lt"}, "isError": {"VarKey": null, "Value": "0"}}, "OutputParams": {}, "IfSteps": null, "ElseSteps": null, "Note": "", "Disabled": false, "Collapsed": false, "DelayMs": 0, "Id": "9296e30b-6716-416a-9df3-fe519a55188e"}], "ElseSteps": null, "Note": "无文本时提示并退出", "Disabled": false, "Collapsed": false, "DelayMs": 0, "Id": "3d5d8a96-66fa-42dc-be28-cf820e601edb"}, {"StepRunnerKey": "sys:csscript", "InputParams": {"mode": {"VarKey": null, "Value": "normal"}, "script": {"VarKey": null, "Value": "public static string Exec(Quicker.Public.IStepContext context)
{
    var text = context.GetVarValue("selectedText") as string;
    var config = context.GetVarValue("config");
    string operation = "";

    // 从词典中读取 operation（C# 5.0 写法）
    var dict = config as System.Collections.Generic.IDictionary<string, object>;
    if (dict != null)
    {
        if (dict.ContainsKey("operation"))
            operation = dict["operation"] as string;
    }

    string result;
    int charCount = text.Length;

    if (operation == "转大写")
        result = text.ToUpper();
    else if (operation == "转小写")
        result = text.ToLower();
    else if (operation == "首字母大写")
    {
        if (text.Length > 0)
            result = char.ToUpper(text[0]) + text.Substring(1);
        else
            result = text;
    }
    else if (operation == "反转文本")
    {
        var chars = text.ToCharArray();
        System.Array.Reverse(chars);
        result = new string(chars);
    }
    else if (operation == "Base64编码")
        result = System.Convert.ToBase64String(System.Text.Encoding.UTF8.GetBytes(text));
    else if (operation == "Base64解码")
    {
        try { result = System.Text.Encoding.UTF8.GetString(System.Convert.FromBase64String(text)); }
        catch { result = "Base64解码失败"; }
    }
    else if (operation == "字符数统计")
        result = string.Format("字符数: {0}", charCount);
    else
        result = text;

    context.SetVarValue("result", result);
    context.SetVarValue("charCount", charCount);
    return result;
